254→private fun ASTNode.replaceWhitespaceWith(text: String) {
255→    require(this.elementType == WHITE_SPACE)
256→    if (this.text != text) {
257→        (this.psi as LeafElement).rawReplaceWithText(text)
258→    }
259→}
