285→    get() {
286→        var leaf = this.prevLeaf()
287→        var offsetToTheLeft = 0
288→        while (leaf != null) {
289→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
290→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
291→                break
292→            }
293→            offsetToTheLeft += leaf.textLength
294→            leaf = leaf.prevLeaf()
295→        }
296→        return offsetToTheLeft + 1
297→    }
