327→/**
328→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
329→ * the boundary nodes [from] or [to] contains a newline.
330→ */
331→public fun hasNewLineInClosedRange(
332→    from: ASTNode,
333→    to: ASTNode,
334→): Boolean =
335→    from.isWhiteSpaceWithNewline() ||
336→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
337→        to.isWhiteSpaceWithNewline()
338→
339→/**
340→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
341→ * should not contain a newline.
342→ */
343→public fun noNewLineInClosedRange(
344→    from: ASTNode,
345→    to: ASTNode,
346→): Boolean =
347→    !from.isWhiteSpaceWithNewline() &&
348→        leavesInOpenRange(from, to).none { it.textContains('\n') } &&
349→        !to.isWhiteSpaceWithNewline()
350→
351→/**
352→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
353→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
354→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
355→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
356→ */
357→public fun leavesInOpenRange(
358→    from: ASTNode,
359→    to: ASTNode,
360→): Sequence<ASTNode> =
361→    from
362→        .leaves()
363→        .takeWhile { it != to && it != to.firstChildNode }
