import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class AnnotationRuleTypeArgumentListTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given a type argument containing multiple annotations on the same line then wrap them`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()
        val formattedCode =
            """
            data class FooRequestDto(
                val data: List<
                    @Valid
                    @NotNull
                    FooDto
                >,
            )
            """.trimIndent()
        annotationRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 20, "Type argument with multiple annotations should be placed on a separate line"),
                LintViolation(2, 20, "Annotation must be placed on separate line"),
                LintViolation(2, 27, "Multiple annotations should not be placed on the same line as the annotated construct"),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a type argument containing multiple annotations each on their own line then do not report`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<
                    @Valid
                    @NotNull
                    FooDto
                >,
            )
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }
}
